// ICP Scoring Model for Interactly.AI Healthcare GTM
// Weights calibrated for healthcare admin automation buyer

const lead = $input.first().json;

let score = 0;
const breakdown = {};

// --- ORGANIZATION SIZE (20 points max) ---
const providers = parseInt(lead.num_providers) || 0;
if (providers >= 10 && providers <= 200) {
  breakdown.org_size = 20;
} else if (providers >= 5 && providers < 10) {
  breakdown.org_size = 12;
} else if (providers > 200) {
  breakdown.org_size = 15; // large but slower sales cycle
} else {
  breakdown.org_size = 5;
}

// --- SPECIALTY MATCH (15 points max) ---
const highAdminSpecialties = ['radiology', 'cardiology', 'orthopedics', 'oncology', 'gastroenterology'];
const specialty = (lead.specialty || '').toLowerCase();
if (highAdminSpecialties.some(s => specialty.includes(s))) {
  breakdown.specialty = 15; // high prior-auth burden specialties
} else if (specialty.includes('primary') || specialty.includes('family') || specialty.includes('internal')) {
  breakdown.specialty = 10; // high volume, moderate complexity
} else if (specialty.includes('urgent') || specialty.includes('multi')) {
  breakdown.specialty = 12;
} else {
  breakdown.specialty = 6;
}

// --- EHR VENDOR (10 points max) ---
const ehr = (lead.ehr_vendor || '').toLowerCase();
if (ehr.includes('epic') || ehr.includes('cerner')) {
  breakdown.ehr = 10; // legacy, integration-ready, high admin burden
} else if (ehr.includes('athena') || ehr.includes('eclinical') || ehr.includes('nextgen')) {
  breakdown.ehr = 8;
} else if (ehr.includes('allscripts') || ehr.includes('meditech')) {
  breakdown.ehr = 7;
} else {
  breakdown.ehr = 4;
}

// --- PAIN SIGNAL STRENGTH (25 points max) ---
let painScore = 0;
const signals = lead.pain_signals || [];
if (signals.includes('job_posting_admin')) painScore += 8;
if (signals.includes('negative_reviews')) painScore += 6;
if (signals.includes('high_denial_rate')) painScore += 7;
if (signals.includes('staff_turnover')) painScore += 4;
breakdown.pain = Math.min(painScore, 25);

// --- INTENT SIGNAL RECENCY (20 points max) ---
const daysSinceSignal = parseInt(lead.days_since_signal) || 999;
if (daysSinceSignal <= 7) {
  breakdown.recency = 20;
} else if (daysSinceSignal <= 30) {
  breakdown.recency = 12;
} else if (daysSinceSignal <= 90) {
  breakdown.recency = 5;
} else {
  breakdown.recency = 0;
}

// --- GEOGRAPHIC FIT (10 points max) ---
const highDensityStates = ['CA', 'TX', 'FL', 'NY', 'PA', 'IL', 'OH', 'GA', 'NC', 'MI'];
const state = (lead.state || '').toUpperCase();
breakdown.geo = highDensityStates.includes(state) ? 10 : 5;

// --- CALCULATE TOTAL ---
score = Object.values(breakdown).reduce((a, b) => a + b, 0);

// --- DETERMINE TIER ---
let tier, action;
if (score >= 80) {
  tier = 'HOT';
  action = 'priority_sequence';
} else if (score >= 50) {
  tier = 'WARM';
  action = 'nurture_sequence';
} else if (score >= 20) {
  tier = 'COOL';
  action = 'monthly_drip';
} else {
  tier = 'COLD';
  action = 'archive';
}

return [{
  json: {
    ...lead,
    icp_score: score,
    icp_tier: tier,
    icp_action: action,
    score_breakdown: breakdown,
    scored_at: new Date().toISOString()
  }
}];

